  1	import * as React from 'react';
  2	import { DeploymentModel, NodeModel } from '@odf/shared/models';
  3	import { getUID } from '@odf/shared/selectors';
  4	import { K8sKind } from '@openshift-console/dynamic-plugin-sdk';
  5	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk-internal/lib/extensions/console-types';
  6	import { SVGIconProps } from '@patternfly/react-icons/dist/esm/createIcon';
  7	import DefaultIcon from '@patternfly/react-icons/dist/esm/icons/builder-image-icon';
  8	import useDetailsLevel from '@patternfly/react-topology/dist/esm/hooks/useDetailsLevel';
  9	import classNames from 'classnames';
 10	import { TFunction } from 'react-i18next';
 11	import { Tooltip } from '@patternfly/react-core';
 12	import {
 13	  ContainerNodeIcon,
 14	  CubeIcon,
 15	  LevelDownAltIcon,
 16	} from '@patternfly/react-icons';
 17	import {
 18	  Decorator,
 19	  DEFAULT_DECORATOR_RADIUS,
 20	  DEFAULT_LAYER,
 21	  DefaultNode,
 22	  getDefaultShapeDecoratorCenter,
 23	  Layer,
 24	  Node,
 25	  NodeShape,
 26	  observer,
 27	  ScaleDetailsLevel,
 28	  ShapeProps,
 29	  TOP_LAYER,
 30	  TopologyQuadrant,
 31	  useHover,
 32	  WithContextMenuProps,
 33	  WithCreateConnectorProps,
 34	  WithDragNodeProps,
 35	  WithSelectionProps,
 36	  useVisualizationController,
 37	  NodeStatus,
 38	} from '@patternfly/react-topology';
 39	import useAlerts from '../../monitoring/useAlert';
 40	import { useCustomTranslation } from '../../useCustomTranslationHook';
 41	import { TopologyDataContext } from '../Context';
 42	import { TopologySearchContext } from '../Context/SearchContext';
 43	import { getStatusWithDescriptors } from '../utils';
 44	import './StyleNode.scss';
 45	
 46	const getResourceModel = (resource: K8sResourceCommon): K8sKind => {
 47	  if (resource?.kind === NodeModel.kind) {
 48	    return NodeModel;
 49	  }
 50	  if (resource?.kind === DeploymentModel.kind) {
 51	    return DeploymentModel;
 52	  }
 53	  return DeploymentModel;
 54	};
 55	
 56	const ICON_PADDING = 20;
 57	
 58	type StyleNodeProps = {
 59	  element: Node;
 60	  getCustomShape?: (node: Node) => React.FunctionComponent<ShapeProps>;
 61	  getShapeDecoratorCenter?: (
 62	    quadrant: TopologyQuadrant,
 63	    node: Node
 64	  ) => { x: number; y: number };
 65	  showLabel?: boolean; // Defaults to true
 66	  labelIcon?: React.ComponentClass<SVGIconProps>;
 67	  showStatusDecorator?: boolean; // Defaults to false
 68	  regrouping?: boolean;
 69	  dragging?: boolean;
 70	} & Partial<
 71	  WithContextMenuProps &
 72	    WithCreateConnectorProps &
 73	    WithDragNodeProps &
 74	    WithSelectionProps
 75	>;
 76	
 77	const getTypeIcon = (resourceKind?: string): React.ComponentClass<any, any> => {
 78	  switch (resourceKind) {
 79	    case NodeModel.kind:
 80	      return ContainerNodeIcon;
 81	    case DeploymentModel.kind:
 82	      return CubeIcon;
 83	    default:
 84	      return DefaultIcon;
 85	  }
 86	};
 87	
 88	const renderIcon = (data: any, element: Node): React.ReactNode => {
 89	  const { width, height } = element.getDimensions();
 90	  const shape = element.getNodeShape();
 91	  const iconSize =
 92	    (shape === NodeShape.trapezoid ? width : Math.min(width, height)) -
 93	    (shape === NodeShape.stadium ? 5 : ICON_PADDING) * 2;
 94	  const Component = getTypeIcon(data.kind || data?.resource?.kind);
 95	
 96	  return (
 97	    <g
 98	      transform={`translate(${(width - iconSize) / 2}, ${
 99	        (height - iconSize) / 2
100	      })`}
101	    >
102	      <Component width={iconSize} height={iconSize} />
103	    </g>
104	  );
105	};
106	
107	const renderDecorator = (
108	  element: Node,
109	  quadrant: TopologyQuadrant,
110	  icon: React.ReactNode,
111	  decoratorRef: React.RefObject<SVGGElement>,
112	  getShapeDecoratorCenter?: (
113	    quadrant: TopologyQuadrant,
114	    node: Node,
115	    radius?: number
116	  ) => {
117	    x: number;
118	    y: number;
119	  },
120	  tooltip?: string,
121	  onClick?: any
122	): React.ReactNode => {
123	  const { x, y } = getShapeDecoratorCenter
124	    ? getShapeDecoratorCenter(quadrant, element)
125	    : getDefaultShapeDecoratorCenter(quadrant, element);
126	
127	  /**
128	   * "attachments" prop of "DefaultNode" does not work if passed element is wrapped around a "div".
129	   * Ref: https://developer.mozilla.org/en-US/docs/Web/SVG/Element/g#usage_notes.
130	   * "Tooltip" is automatically wrapping its children around a "div" in PF5.
131	   * Using "triggerRef" instead, as a workaround.
132	   */
133	  return (
134	    <>
135	      <Tooltip content={tooltip} triggerRef={decoratorRef} />
136	      <Decorator
137	        innerRef={decoratorRef}
138	        x={x}
139	        y={y}
140	        radius={DEFAULT_DECORATOR_RADIUS}
141	        showBackground
142	        icon={icon}
143	        onClick={onClick}
144	      />
145	    </>
146	  );
147	};
148	
149	const renderDecorators = (
150	  element: Node,
151	  data: any,
152	  decoratorRef: React.RefObject<SVGGElement>,
153	  t: TFunction<string>,
154	  getShapeDecoratorCenter?: (
155	    quadrant: TopologyQuadrant,
156	    node: Node
157	  ) => {
158	    x: number;
159	    y: number;
160	  }
161	): React.ReactNode => {
162	  if (!data.showDecorators) {
163	    return null;
164	  }
165	  const onStepOntoClick = () => {
166	    element.getController().fireEvent('STEP_INTO_EVENT', {
167	      ...data,
168	      id: element.getId(),
169	    });
170	  };
171	
172	  return (
173	    <>
174	      {data.canStepInto &&
175	        renderDecorator(
176	          element,
177	          TopologyQuadrant.lowerRight,
178	          <LevelDownAltIcon />,
179	          decoratorRef,
180	          getShapeDecoratorCenter,
181	          t('Enter node'),
182	          onStepOntoClick
183	        )}
184	    </>
185	  );
186	};
187	
188	const StyleNode: React.FunctionComponent<StyleNodeProps> = ({
189	  element,
190	  onContextMenu,
191	  contextMenuOpen,
192	  showLabel,
193	  dragging,
194	  regrouping,
195	  onHideCreateConnector,
196	  ...rest
197	}) => {
198	  const decoratorRef = React.useRef<SVGGElement>();
199	
200	  const data = element.getData();
201	  const controller = useVisualizationController();
202	  const detailsLevel = useDetailsLevel();
203	  const [hover, hoverRef] = useHover();
204	
205	  const { t } = useCustomTranslation();
206	
207	  const { activeItemsUID, activeItem } = React.useContext(
208	    TopologySearchContext
209	  );
210	  const { nodeDeploymentMap } = React.useContext(TopologyDataContext);
211	  // Change this to search query instead
212	
213	  const [alerts] = useAlerts();
214	
215	  const resource: K8sResourceCommon = data.resource;
216	  const resourceModel = getResourceModel(resource);
217	
218	  const isSearchActive = activeItemsUID.length > 0;
219	
220	  const { status, message } = React.useMemo(() => {
221	    if (!resource) return { status: NodeStatus.default, message: '' };
222	    return getStatusWithDescriptors(
223	      resourceModel,
224	      nodeDeploymentMap,
225	      resource,
226	      alerts,
227	      t
228	    );
229	  }, [resource, resourceModel, nodeDeploymentMap, alerts, t]);
230	  const resourceUID = getUID(resource);
231	  const isElementActive = activeItemsUID.includes(resourceUID);
232	  const highlightNode = activeItem === resourceUID;
233	
234	  React.useEffect(() => {
235	    if (highlightNode) {
236	      controller
237	        .getGraph()
238	        .panIntoView(element, { minimumVisible: 200, offset: 100 });
239	    }
240	  }, [highlightNode, controller, element]);
241	
242	  const classnames = classNames(
243	    { 'odf-topology__filter': isSearchActive },
244	    { 'odf-topology__filter--active': isElementActive }
245	  );
246	
247	  const passedData = React.useMemo(() => {
248	    const newData = { ...data };
249	    Object.keys(newData).forEach((key) => {
250	      if (newData[key] === undefined) {
251	        delete newData[key];
252	      }
253	    });
254	    return newData;
255	  }, [data]);
256	
257	  React.useEffect(() => {
258	    if (detailsLevel === ScaleDetailsLevel.low) {
259	      onHideCreateConnector && onHideCreateConnector();
260	    }
261	  }, [detailsLevel, onHideCreateConnector]);
262	
263	  const LabelIcon = passedData.labelIcon;
264	  return (
265	    <Layer id={hover ? TOP_LAYER : DEFAULT_LAYER}>
266	      <g ref={hoverRef}>
267	        <DefaultNode
268	          className={classnames}
269	          element={element}
270	          scaleLabel={detailsLevel !== ScaleDetailsLevel.low}
271	          scaleNode={hover && detailsLevel === ScaleDetailsLevel.low}
272	          {...rest}
273	          {...passedData}
274	          dragging={dragging}
275	          regrouping={regrouping}
276	          showLabel={
277	            hover || (detailsLevel !== ScaleDetailsLevel.low && showLabel)
278	          }
279	          showStatusBackground={
280	            !hover && detailsLevel === ScaleDetailsLevel.low
281	          }
282	          showStatusDecorator={
283	            detailsLevel === ScaleDetailsLevel.high &&
284	            passedData.showStatusDecorator
285	          }
286	          onStatusDecoratorClick={() => null}
287	          onContextMenu={data.showContextMenu ? onContextMenu : undefined}
288	          contextMenuOpen={contextMenuOpen}
289	          onShowCreateConnector={null}
290	          onHideCreateConnector={null}
291	          labelIcon={LabelIcon && <LabelIcon noVerticalAlign />}
292	          attachments={
293	            (hover || detailsLevel === ScaleDetailsLevel.high) &&
294	            renderDecorators(
295	              element,
296	              passedData,
297	              decoratorRef,
298	              t,
299	              rest.getShapeDecoratorCenter
300	            )
301	          }
302	          {...(highlightNode ? { selected: true } : {})}
303	          nodeStatus={status}
304	          statusDecoratorTooltip={message}
305	        >
306	          {(hover || detailsLevel !== ScaleDetailsLevel.low) &&
307	            renderIcon(passedData, element)}
308	        </DefaultNode>
309	      </g>
310	    </Layer>
311	  );
312	};
313	
314	export default observer(StyleNode);

